21	// US-038 вҖ” Creator Discover feed. Renders a header Chip toggle for
22	// "Eligible only" plus a pull-to-refresh list of CampaignCards sourced from
23	// the `list_discover_feed(p_eligible_only)` SECURITY DEFINER RPC (see the
24	// us_038 migration for rationale вҖ” a plain PostgREST embed would silently
25	// null lister_handle under the self-only users RLS policy).
26	//
27	// Persistence: the toggle state is stored in AsyncStorage under
28	// FILTER_STORAGE_KEY (spec says MMKV but Codebase Pattern #91 rules MMKV
29	// out under Expo Go; a non-secret boolean preference doesn't warrant the
30	// SecureStore ceremony either, so AsyncStorage is the right fit).
31	// Default is eligible_only=true per AC.
32	//
33	// Empty state per docs/design.md В§5.5 вҖ” the "See all campaigns" action
34	// flips the toggle off (which reloads) rather than routing elsewhere.
35	
36	type DiscoverRow = Database['public']['Functions']['list_discover_feed']['Returns'][number];
37	
38	const FILTER_STORAGE_KEY = 'marketify.discoverEligibleOnly';
39	const HYDRATED_DEFAULT = true;
40	
41	function readCurrency(raw: string): 'USD' | 'EUR' | 'GBP' {
42	  return raw === 'EUR' || raw === 'GBP' ? raw : 'USD';
43	}
