45	export default function Feed() {
46	  // Toggle is hydrated async from AsyncStorage вҖ” until the read settles we
47	  // render with the default and flip in place once storage returns. This
48	  // matches the storage-hydration pattern from AuthProvider (Pattern #97).
49	  const [eligibleOnly, setEligibleOnly] = useState<boolean>(HYDRATED_DEFAULT);
50	  const [hydrated, setHydrated] = useState<boolean>(false);
51	
52	  const [rows, setRows] = useState<DiscoverRow[]>([]);
53	  const [loading, setLoading] = useState<boolean>(true);
54	  const [refreshing, setRefreshing] = useState<boolean>(false);
55	  const [error, setError] = useState<string | null>(null);
56	
57	  // Synchronous ref mirrors the latest toggle value so the `load` callback
58	  // never stale-captures it (Pattern #106). React state still drives the UI.
59	  const eligibleRef = useRef<boolean>(HYDRATED_DEFAULT);
60	
61	  useEffect(() => {
62	    let cancelled = false;
63	    void AsyncStorage.getItem(FILTER_STORAGE_KEY).then((raw) => {
64	      if (cancelled) return;
65	      const next = raw === null ? HYDRATED_DEFAULT : raw === 'true';
66	      eligibleRef.current = next;
67	      setEligibleOnly(next);
68	      setHydrated(true);
69	    });
70	    return () => {
71	      cancelled = true;
72	    };
73	  }, []);
74	
75	  const load = useCallback(async (isRefresh: boolean) => {
76	    if (isRefresh) setRefreshing(true);
77	    else setLoading(true);
78	    setError(null);
79	
80	    const { data, error: rpcError } = await supabase.rpc('list_discover_feed', {
81	      p_eligible_only: eligibleRef.current,
82	    });
83	    if (rpcError) {
84	      setError("Couldn't load campaigns.");
85	      setRows([]);
86	    } else {
87	      setRows(data ?? []);
88	    }
89	    if (isRefresh) setRefreshing(false);
90	    else setLoading(false);
91	  }, []);
92	
93	  // Re-fetch whenever the toggle changes, but only after hydration вҖ” the
94	  // first effect run will otherwise fire twice (once with the default,
95	  // once with the hydrated value).
96	  useEffect(() => {
97	    if (!hydrated) return;
98	    eligibleRef.current = eligibleOnly;
99	    void load(false);
100	  }, [eligibleOnly, hydrated, load]);
101	
102	  const onToggleEligible = useCallback(() => {
103	    setEligibleOnly((prev) => {
104	      const next = !prev;
105	      void AsyncStorage.setItem(FILTER_STORAGE_KEY, next ? 'true' : 'false');
106	      return next;
107	    });
108	  }, []);
109	
110	  const onRefresh = useCallback(() => {
111	    void load(true);
112	  }, [load]);
113	
114	  const onCardPress = useCallback((id: string) => {
115	    router.push(`/(creator)/listing/${id}`);
116	  }, []);
117	
118	  return (
119	    <SafeAreaView style={styles.root}>
120	      <ScrollView
121	        contentContainerStyle={styles.scroll}
122	        refreshControl={
123	          <RefreshControl refreshing={refreshing} onRefresh={onRefresh} tintColor={colors.ink} />
124	        }
125	      >
126	        <Text style={[textStyles.display, styles.header]}>Discover</Text>
127	
128	        <View style={styles.filterRow}>
129	          <Chip
130	            label="Eligible only"
131	            active={eligibleOnly}
132	            onPress={onToggleEligible}
133	            testID="chip-eligible-only"
134	          />
135	        </View>
136	
137	        {loading ? (
138	          <View style={styles.list} testID="discover-loading">
139	            <SkeletonCard />
140	            <SkeletonCard />
141	            <SkeletonCard />
142	          </View>
143	        ) : error ? (
144	          <View style={styles.emptyBox}>
145	            <Text style={[textStyles.body, { color: colors.danger }]}>{error}</Text>
146	          </View>
147	        ) : rows.length === 0 ? (
148	          <EmptyState
149	            eligibleOnly={eligibleOnly}
150	            onSeeAll={() => {
151	              if (!eligibleOnly) return;
152	              setEligibleOnly(false);
153	              void AsyncStorage.setItem(FILTER_STORAGE_KEY, 'false');
154	            }}
155	          />
156	        ) : (
157	          <View style={styles.list} testID="discover-list">
158	            {rows.map((r) => (
159	              <CampaignCard
160	                key={r.id}
161	                title={r.title}
162	                listerHandle={`@${r.lister_handle}`}
163	                priceCents={r.price_cents}
164	                currency={readCurrency(r.currency)}
165	                onPress={() => onCardPress(r.id)}
166	                testID={`campaign-card-${r.id}`}
167	              />
168	            ))}
169	          </View>
170	        )}
171	      </ScrollView>
172	    </SafeAreaView>
173	  );
174	}
175	
176	// Empty state per docs/design.md В§5.5. Two action cards: "Refresh your
177	// metrics" routes to Profile (which has its own refresh affordance from
178	// US-036); "See all campaigns" flips the eligibility toggle off in place.
179	// The latter is hidden when the toggle is already off вҖ” nothing to flip.
180	function EmptyState({
181	  eligibleOnly,
182	  onSeeAll,
183	}: {
184	  eligibleOnly: boolean;
185	  onSeeAll: () => void;
186	}) {
187	  return (
188	    <View style={styles.emptyRoot} testID="discover-empty">
189	      <Text style={[textStyles.h1, styles.emptyHeadline]}>Nothing matches you вҖ” yet.</Text>
190	      <Text style={[textStyles.body, styles.emptyBody]}>
191	        Campaigns get added daily. Meanwhile, here&apos;s what to try.
192	      </Text>
193	
194	      <Pressable
195	        style={[styles.actionCard, shadows.hard]}
196	        onPress={() => router.push('/(creator)/profile')}
197	        accessibilityRole="button"
198	        accessibilityLabel="Refresh your metrics"
199	        testID="empty-action-refresh"
200	      >
201	        <Text style={[textStyles.h2, { color: colors.ink }]}>Refresh your metrics</Text>
202	        <Text style={[textStyles.caption, { color: colors.ink70 }]}>
203	          Your follower counts may be out of date.
204	        </Text>
205	      </Pressable>
206	
207	      {eligibleOnly ? (
208	        <Pressable
209	          style={[styles.actionCard, shadows.hard]}
210	          onPress={onSeeAll}
211	          accessibilityRole="button"
212	          accessibilityLabel="See all campaigns"
213	          testID="empty-action-see-all"
214	        >
215	          <Text style={[textStyles.h2, { color: colors.ink }]}>See all campaigns</Text>
216	          <Text style={[textStyles.caption, { color: colors.ink70 }]}>
217	            Turn off the eligibility filter.
218	          </Text>
219	        </Pressable>
220	      ) : null}
221	    </View>
222	  );
223	}
